3	import { useState, useMemo } from "react";
4	import useSWR, { mutate } from "swr";
5	import {
6	  subscriptions as subsApi,
7	  channels as channelsApi,
8	  projects as projectsApi,
9	  sources as sourcesApi,
10	} from "@/lib/api/client";
11	import type { Source, Subscription } from "@/lib/api/types";
12	import { Plus, Pencil, Trash2, ChevronRight } from "lucide-react";
13	import { Checkbox } from "@/components/ui/checkbox";
14	import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
15	import { ConfirmDialog } from "@/components/ui/confirm-dialog";
16	import { SubscriptionForm } from "@/components/subscriptions/subscription-form";
17	import { useTranslation } from "@/lib/i18n/context";
18	
19	const SUB_TYPE_COLORS: Record<string, { bg: string; text: string }> = {
20	  source_release: { bg: "#1a1a1a", text: "#ffffff" },
21	  semantic_release: { bg: "#2563eb", text: "#ffffff" },
22	};
23	
24	function SubTypeBadge({ type }: { type: string }) {
25	  const colors = SUB_TYPE_COLORS[type] ?? { bg: "#6b7280", text: "#ffffff" };
26	  return (
27	    <span
28	      className="inline-flex items-center rounded-full px-2.5 py-0.5"
29	      style={{
30	        backgroundColor: colors.bg,
31	        color: colors.text,
32	        fontFamily: "var(--font-dm-sans)",
33	        fontSize: "12px",
34	        fontWeight: 500,
35	        lineHeight: "16px",
36	      }}
37	    >
38	      {type}
39	    </span>
40	  );
41	}
42	
43	export default function SubscriptionsPage() {
44	  const { t } = useTranslation();
45	  const { data, isLoading } = useSWR("subscriptions", () => subsApi.list());
46	  const { data: channelsData } = useSWR("channels-for-sub-list", () =>
47	    channelsApi.list()
48	  );
49	  const { data: projectsData } = useSWR("projects-for-sub-list", () =>
50	    projectsApi.list(1, 100)
51	  );
52	
53	  // Collect unique source IDs from subscriptions and fetch each one
54	  const sourceIds = useMemo(
55	    () =>
56	      Array.from(
57	        new Set(
58	          (data?.data ?? [])
59	            .filter((s) => s.type === "source_release" && s.source_id)
60	            .map((s) => s.source_id!)
61	        )
62	      ),
63	    [data]
64	  );
65	  const { data: sourcesMap } = useSWR(
66	    sourceIds.length > 0 ? `sources-for-sub-list-${sourceIds.join(",")}` : null,
67	    async () => {
68	      const results = await Promise.all(
69	        sourceIds.map((id) => sourcesApi.get(id).catch(() => null))
70	      );
71	      const map: Record<string, Source> = {};
72	      for (const r of results) {
73	        if (r?.data) map[r.data.id] = r.data;
74	      }
75	      return map;
76	    }
77	  );
78	
79	  const [createOpen, setCreateOpen] = useState(false);
80	  const [editingSub, setEditingSub] = useState<Subscription | null>(null);
81	  const [deletingId, setDeletingId] = useState<string | null>(null);
82	  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
83	  const [batchDeleteOpen, setBatchDeleteOpen] = useState(false);
84	  const [collapsedChannels, setCollapsedChannels] = useState<Set<string>>(new Set());
85	
86	  const getChannelName = (id: string) =>
87	    channelsData?.data.find((c) => c.id === id)?.name ?? id;
88	
89	  const getChannelType = (id: string) =>
90	    channelsData?.data.find((c) => c.id === id)?.type ?? "";
91	
92	  const getProjectName = (id: string) =>
93	    projectsData?.data.find((p) => p.id === id)?.name ?? id;
94	
95	  const getSourceLabel = (id: string) => {
96	    const source = sourcesMap?.[id];
97	    return source ? `${source.provider}: ${source.repository}` : id;
98	  };
99	
100	  const subscriptions = data?.data ?? [];
101	
102	  // Group subscriptions by channel_id
103	  const grouped = useMemo(() => {
104	    const map = new Map<string, Subscription[]>();
105	    for (const sub of subscriptions) {
106	      const list = map.get(sub.channel_id) ?? [];
107	      list.push(sub);
108	      map.set(sub.channel_id, list);
109	    }
110	    return map;
111	  }, [subscriptions]);
112	
113	  const isAllSelected = subscriptions.length > 0 && selectedIds.size === subscriptions.length;
114	  const isSomeSelected = selectedIds.size > 0 && !isAllSelected;
115	
116	  const toggleSelect = (id: string) => {
117	    setSelectedIds((prev) => {
118	      const next = new Set(prev);
119	      if (next.has(id)) next.delete(id);
120	      else next.add(id);
121	      return next;
122	    });
123	  };
124	
125	  const toggleSelectAll = () => {
126	    if (isAllSelected) {
127	      setSelectedIds(new Set());
128	    } else {
129	      setSelectedIds(new Set(subscriptions.map((s) => s.id)));
130	    }
131	  };
132	
133	  const toggleChannel = (channelId: string) => {
134	    setCollapsedChannels((prev) => {
135	      const next = new Set(prev);
136	      if (next.has(channelId)) next.delete(channelId);
137	      else next.add(channelId);
138	      return next;
139	    });
140	  };
141	
142	  const toggleSelectChannel = (channelId: string) => {
143	    const channelSubs = grouped.get(channelId) ?? [];
144	    const channelSubIds = channelSubs.map((s) => s.id);
145	    const allSelected = channelSubIds.every((id) => selectedIds.has(id));
146	    setSelectedIds((prev) => {
147	      const next = new Set(prev);
148	      if (allSelected) {
149	        channelSubIds.forEach((id) => next.delete(id));
150	      } else {
151	        channelSubIds.forEach((id) => next.add(id));
152	      }
153	      return next;
154	    });
155	  };
156	
157	  const clearSelection = () => setSelectedIds(new Set());
158	
159	  return (
160	    <div className="space-y-6">
161	      {/* Header */}
162	      <div className="flex items-center justify-between">
163	        <div>
164	          <h1
165	            className="text-foreground"
166	            style={{
167	              fontFamily: "var(--font-raleway)",
168	              fontSize: "24px",
169	              fontWeight: 700,
170	            }}
171	          >
172	            {t("subscriptions.title")}
173	          </h1>
174	          <p className="mt-1 text-[13px] text-text-secondary" style={{ fontFamily: "var(--font-dm-sans)" }}>
175	            {t("subscriptions.description")}
176	          </p>
177	        </div>
178	        <button
179	          onClick={() => setCreateOpen(true)}
180	          className="inline-flex items-center gap-1.5 rounded-md px-3.5 py-2 transition-colors hover:opacity-90 bg-beacon-accent text-white"
181	          style={{
182	            fontFamily: "var(--font-dm-sans)",
183	            fontSize: "13px",
184	            fontWeight: 500,
185	          }}
186	        >
187	          <Plus className="h-4 w-4" />
188	          {t("subscriptions.newSubscription")}
189	        </button>
190	      </div>
191	
192	      {isLoading ? (
193	        <div
194	          className="overflow-hidden rounded-lg bg-surface py-16 text-center border-border"
195	          style={{ border: "1px solid var(--border)", fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "var(--text-secondary)" }}
196	        >
197	          {t("subscriptions.loading")}
198	        </div>
199	      ) : subscriptions.length === 0 ? (
200	        <div
201	          className="overflow-hidden rounded-lg bg-surface py-16 text-center border-border"
202	          style={{ border: "1px solid var(--border)" }}
203	        >
204	          <p
205	            className="text-text-muted"
206	            style={{
207	              fontFamily: "var(--font-raleway)",
208	              fontStyle: "italic",
209	              fontSize: "15px",
210	            }}
211	          >
212	            {t("subscriptions.empty")}
213	          </p>
214	        </div>
215	      ) : (
216	        <>
217	          {/* Select all / batch bar */}
218	          <div
219	            className="flex items-center gap-3 rounded-lg bg-surface px-5 py-2.5"
220	            style={{ border: "1px solid var(--border)" }}
221	          >
222	            <Checkbox
223	              checked={isAllSelected ? true : isSomeSelected ? "indeterminate" : false}
224	              onCheckedChange={toggleSelectAll}
225	            />
226	            <span
227	              className="text-text-secondary"
228	              style={{
229	                fontFamily: "var(--font-dm-sans)",
230	                fontSize: "13px",
231	              }}
232	            >
233	              {selectedIds.size > 0
234	                ? t("subscriptions.selected").replace("{count}", String(selectedIds.size)).replace("{total}", String(subscriptions.length))
235	                : subscriptions.length === 1
236	                  ? t("subscriptions.countLabel").replace("{count}", String(subscriptions.length))
237	                  : t("subscriptions.countLabelPlural").replace("{count}", String(subscriptions.length))}
238	            </span>
239	            {selectedIds.size > 0 && (
240	              <button
241	                onClick={() => setBatchDeleteOpen(true)}
242	                className="ml-auto inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 transition-colors hover:opacity-90"
243	                style={{
244	                  backgroundColor: "#dc2626",
245	                  color: "#ffffff",
246	                  fontFamily: "var(--font-dm-sans)",
247	                  fontSize: "13px",
248	                  fontWeight: 500,
249	                }}
250	              >
251	                <Trash2 className="h-3.5 w-3.5" />
252	                {t("subscriptions.deleteSelected")}
253	              </button>
254	            )}
255	          </div>
256	
257	          {/* Grouped by channel */}
258	          <div className="space-y-3">
259	            {Array.from(grouped.entries()).map(([channelId, channelSubs]) => {
260	              const isCollapsed = collapsedChannels.has(channelId);
261	              const channelSubIds = channelSubs.map((s) => s.id);
262	              const allChannelSelected = channelSubIds.every((id) => selectedIds.has(id));
263	              const someChannelSelected = channelSubIds.some((id) => selectedIds.has(id)) && !allChannelSelected;
264	              const channelType = getChannelType(channelId);
265	
266	              return (
267	                <div
268	                  key={channelId}
269	                  className="overflow-hidden rounded-lg bg-surface"
270	                  style={{ border: "1px solid var(--border)" }}
271	                >
272	                  {/* Channel header */}
273	                  <div
274	                    className="flex items-center gap-3 px-5 py-3 cursor-pointer select-none bg-background"
275	                    style={{ borderBottom: isCollapsed ? "none" : "1px solid var(--border)" }}
276	                    onClick={() => toggleChannel(channelId)}
277	                  >
278	                    <div onClick={(e) => e.stopPropagation()}>
279	                      <Checkbox
280	                        checked={allChannelSelected ? true : someChannelSelected ? "indeterminate" : false}
281	                        onCheckedChange={() => toggleSelectChannel(channelId)}
282	                      />
283	                    </div>
284	                    <ChevronRight
285	                      className="h-4 w-4 transition-transform text-text-muted"
286	                      style={{
287	                        transform: isCollapsed ? "rotate(0deg)" : "rotate(90deg)",
288	                      }}
289	                    />
290	                    <span
291	                      className="text-foreground"
292	                      style={{
293	                        fontFamily: "var(--font-dm-sans)",
294	                        fontSize: "14px",
295	                        fontWeight: 600,
296	                      }}
297	                    >
298	                      {getChannelName(channelId)}
299	                    </span>
300	                    {channelType && (
301	                      <span
302	                        className="rounded-full px-2 py-0.5 text-text-secondary bg-mono-bg"
303	                        style={{
304	                          fontFamily: "var(--font-dm-sans)",
305	                          fontSize: "11px",
306	                          fontWeight: 500,
307	                        }}
308	                      >
309	                        {channelType}
310	                      </span>
311	                    )}
312	                    <span
313	                      className="text-text-muted"
314	                      style={{
315	                        fontFamily: "var(--font-dm-sans)",
316	                        fontSize: "12px",
317	                        marginLeft: "auto",
318	                      }}
319	                    >
320	                      {channelSubs.length === 1
321	                        ? t("subscriptions.channelSubscription").replace("{count}", String(channelSubs.length))
322	                        : t("subscriptions.channelSubscriptionPlural").replace("{count}", String(channelSubs.length))}
323	                    </span>
324	                  </div>
325	
326	                  {/* Subscription rows */}
327	                  {!isCollapsed && (
328	                    <table className="w-full">
329	                      <thead>
330	                        <tr>
331	                          {["", t("subscriptions.thType"), t("subscriptions.thTarget"), t("subscriptions.thVersionFilter"), ""].map(
332	                            (heading, i) => (
333	                              <th
334	                                key={i}
335	                                className={`py-2 text-left ${i === 0 ? "w-10 px-5" : i === 4 ? "w-20 px-5" : "px-5"}`}
336	                                style={{
337	                                  fontFamily: "var(--font-dm-sans)",
338	                                  fontSize: "11px",
339	                                  fontWeight: 500,
340	                                  textTransform: "uppercase",
341	                                  letterSpacing: "0.08em",
342	                                  color: "var(--text-muted)",
343	                                  borderBottom: "1px solid var(--border)",
344	                                }}
345	                              >
346	                                {heading}
347	                              </th>
348	                            )
349	                          )}
350	                        </tr>
351	                      </thead>
352	                      <tbody>
353	                        {channelSubs.map((sub) => (
354	                          <tr
355	                            key={sub.id}
356	                            className="transition-colors hover:bg-background"
357	                            style={{ borderBottom: "1px solid var(--border)" }}
358	                          >
359	                            {/* Checkbox */}
360	                            <td className="w-10 px-5 py-3">
361	                              <Checkbox
362	                                checked={selectedIds.has(sub.id)}
363	                                onCheckedChange={() => toggleSelect(sub.id)}
364	                              />
365	                            </td>
366	
367	                            {/* Type */}
368	                            <td className="px-5 py-3">
369	                              <SubTypeBadge type={sub.type} />
370	                            </td>
371	
372	                            {/* Target */}
373	                            <td
374	                              className="px-5 py-3 text-foreground"
375	                              style={{
376	                                fontFamily: "var(--font-dm-sans)",
377	                                fontSize: "14px",
378	                                fontWeight: 500,
379	                              }}
380	                            >
381	                              {sub.type === "source_release"
382	                                ? getSourceLabel(sub.source_id!)
383	                                : getProjectName(sub.project_id!)}
384	                            </td>
385	
386	                            {/* Version Filter */}
387	                            <td
388	                              className="px-5 py-3"
389	                              style={{
390	                                fontFamily: sub.version_filter
391	                                  ? "'JetBrains Mono', monospace"
392	                                  : "var(--font-dm-sans)",
393	                                fontSize: "13px",
394	                                color: sub.version_filter ? "var(--foreground)" : "var(--text-muted)",
395	                              }}
396	                            >
397	                              {sub.version_filter || "\u2014"}
398	                            </td>
399	
400	                            {/* Actions */}
401	                            <td className="w-20 px-5 py-3">
402	                              <div className="flex items-center gap-2">
403	                                <button
404	                                  onClick={() => setEditingSub(sub)}
405	                                  className="rounded p-1 text-text-muted transition-colors hover:bg-mono-bg hover:text-foreground"
406	                                >
407	                                  <Pencil className="h-4 w-4" />
408	                                </button>
409	                                <button
410	                                  onClick={() => setDeletingId(sub.id)}
411	                                  className="rounded p-1 text-text-muted transition-colors hover:bg-red-50 hover:text-red-600"
412	                                >
413	                                  <Trash2 className="h-4 w-4" />
414	                                </button>
415	                              </div>
416	                            </td>
417	                          </tr>
418	                        ))}
419	                      </tbody>
420	                    </table>
421	                  )}
422	                </div>
423	              );
424	            })}
425	          </div>
426	        </>
427	      )}
428	
429	      {/* Create dialog */}
430	      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
431	        <DialogContent className="sm:max-w-lg">
432	          <DialogHeader>
433	            <DialogTitle>{t("subscriptions.createSubscription")}</DialogTitle>
434	          </DialogHeader>
435	          <SubscriptionForm
436	            title={t("subscriptions.createSubscription")}
437	            onSubmit={async (input) => {
438	              await subsApi.create(input);
439	            }}
440	            onBatchSubmit={async (input) => {
441	              await subsApi.batchCreate(input);
442	            }}
443	            onSuccess={() => {
444	              setCreateOpen(false);
445	              mutate("subscriptions");
446	              clearSelection();
447	            }}
448	            onCancel={() => setCreateOpen(false)}
449	          />
450	        </DialogContent>
451	      </Dialog>
452	
453	      {/* Edit dialog */}
454	      <Dialog
455	        open={!!editingSub}
456	        onOpenChange={(open) => {
457	          if (!open) setEditingSub(null);
458	        }}
459	      >
460	        <DialogContent className="sm:max-w-lg">
461	          <DialogHeader>
462	            <DialogTitle>{t("subscriptions.editSubscription")}</DialogTitle>
463	          </DialogHeader>
464	          {editingSub && (
465	            <SubscriptionForm
466	              key={editingSub.id}
467	              title={t("subscriptions.editSubscription")}
468	              initial={editingSub}
469	              onSubmit={async (input) => {
470	                await subsApi.update(editingSub.id, input);
471	              }}
472	              onSuccess={() => {
473	                setEditingSub(null);
474	                mutate("subscriptions");
475	                clearSelection();
476	              }}
477	              onCancel={() => setEditingSub(null)}
478	            />
479	          )}
480	        </DialogContent>
481	      </Dialog>
482	
483	      {/* Delete dialog */}
484	      <ConfirmDialog
485	        open={!!deletingId}
486	        onOpenChange={(open) => {
487	          if (!open) setDeletingId(null);
488	        }}
489	        title={t("subscriptions.deleteSubscription")}
490	        description={t("subscriptions.deleteSubscriptionDesc")}
491	        onConfirm={async () => {
492	          if (deletingId) {
493	            await subsApi.delete(deletingId);
494	            mutate("subscriptions");
495	            clearSelection();
496	          }
497	        }}
498	      />
499	
500	      {/* Batch delete dialog */}
501	      <ConfirmDialog
502	        open={batchDeleteOpen}
503	        onOpenChange={setBatchDeleteOpen}
504	        title={t("subscriptions.deleteSubscriptions")}
505	        description={t("subscriptions.deleteSubscriptionsDesc").replace("{count}", String(selectedIds.size))}
506	        onConfirm={async () => {
507	          await subsApi.batchDelete({ ids: [...selectedIds] });
508	          mutate("subscriptions");
509	          clearSelection();
510	        }}
511	      />
512	    </div>
513	  );
514	}
