19	import { useTranslation } from "@/lib/i18n/context";
20	
21	const SUB_TYPE_COLORS: Record<string, { bg: string; text: string }> = {
22	  source_release: { bg: "#1a1a1a", text: "#ffffff" },
23	  semantic_release: { bg: "#2563eb", text: "#ffffff" },
24	};
25	
26	function SubTypeBadge({ type }: { type: string }) {
27	  const colors = SUB_TYPE_COLORS[type] ?? { bg: "#6b7280", text: "#ffffff" };
28	  return (
29	    <span
30	      className="inline-flex items-center rounded-full px-2.5 py-0.5"
31	      style={{
32	        backgroundColor: colors.bg,
33	        color: colors.text,
34	        fontFamily: "var(--font-dm-sans)",
35	        fontSize: "12px",
36	        fontWeight: 500,
37	        lineHeight: "16px",
38	      }}
39	    >
40	      {type}
41	    </span>
42	  );
43	}
44	
45	export default function SubscriptionsPage() {
46	  return (
47	    <Suspense>
48	      <SubscriptionsPageInner />
49	    </Suspense>
50	  );
51	}
52	
53	function SubscriptionsPageInner() {
54	  const { t } = useTranslation();
55	  const FILTER_KEYS = ["channel", "type"];
56	  const { filters, setFilters } = useFilterParams(FILTER_KEYS);
57	  const { data, isLoading } = useSWR("subscriptions", () => subsApi.list());
58	  const { data: channelsData } = useSWR("channels-for-sub-list", () =>
59	    channelsApi.list()
60	  );
61	  const { data: projectsData } = useSWR("projects-for-sub-list", () =>
62	    projectsApi.list(1, 100)
63	  );
64	
65	  // Collect unique source IDs from subscriptions and fetch each one
66	  const sourceIds = useMemo(
67	    () =>
68	      Array.from(
69	        new Set(
70	          (data?.data ?? [])
71	            .filter((s) => s.type === "source_release" && s.source_id)
72	            .map((s) => s.source_id!)
73	        )
74	      ),
75	    [data]
76	  );
77	  const { data: sourcesMap } = useSWR(
78	    sourceIds.length > 0 ? `sources-for-sub-list-${sourceIds.join(",")}` : null,
79	    async () => {
80	      const results = await Promise.all(
81	        sourceIds.map((id) => sourcesApi.get(id).catch(() => null))
82	      );
83	      const map: Record<string, Source> = {};
84	      for (const r of results) {
85	        if (r?.data) map[r.data.id] = r.data;
86	      }
87	      return map;
88	    }
89	  );
90	
91	  const [createOpen, setCreateOpen] = useState(false);
92	  const [editingSub, setEditingSub] = useState<Subscription | null>(null);
93	  const [deletingId, setDeletingId] = useState<string | null>(null);
94	  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
95	  const [batchDeleteOpen, setBatchDeleteOpen] = useState(false);
96	  const [collapsedChannels, setCollapsedChannels] = useState<Set<string>>(new Set());
97	
98	  const getChannelName = (id: string) =>
99	    channelsData?.data.find((c) => c.id === id)?.name ?? id;
100	
101	  const getChannelType = (id: string) =>
102	    channelsData?.data.find((c) => c.id === id)?.type ?? "";
103	
104	  const getProjectName = (id: string) =>
105	    projectsData?.data.find((p) => p.id === id)?.name ?? id;
106	
107	  const getSourceLabel = (id: string) => {
108	    const source = sourcesMap?.[id];
109	    return source ? `${source.provider}: ${source.repository}` : id;
110	  };
111	
112	  /* Build filter config */
113	  const filterConfig: FilterConfig[] = useMemo(() => [
114	    {
115	      key: "channel",
116	      label: "Channel",
117	      type: "select" as const,
118	      options: (channelsData?.data ?? []).map((c) => ({ value: c.id, label: c.name })),
119	    },
120	    {
121	      key: "type",
122	      label: "Type",
123	      type: "select" as const,
124	      options: [
125	        { value: "source_release", label: "Source Release" },
126	        { value: "semantic_release", label: "Semantic Release" },
127	      ],
128	    },
129	  ], [channelsData]);
130	
131	  /* Client-side filtering */
132	  const allSubscriptions = data?.data ?? [];
133	  const subscriptions = useMemo(() => {
134	    let result = allSubscriptions;
135	    if (filters.channel) {
136	      result = result.filter((s) => s.channel_id === filters.channel);
137	    }
138	    if (filters.type) {
139	      result = result.filter((s) => s.type === filters.type);
140	    }
141	    return result;
142	  }, [allSubscriptions, filters.channel, filters.type]);
143	
144	  // Group subscriptions by channel_id
145	  const grouped = useMemo(() => {
146	    const map = new Map<string, Subscription[]>();
147	    for (const sub of subscriptions) {
148	      const list = map.get(sub.channel_id) ?? [];
149	      list.push(sub);
150	      map.set(sub.channel_id, list);
151	    }
152	    return map;
153	  }, [subscriptions]);
154	
155	  const isAllSelected = subscriptions.length > 0 && selectedIds.size === subscriptions.length;
156	  const isSomeSelected = selectedIds.size > 0 && !isAllSelected;
157	
158	  const toggleSelect = (id: string) => {
159	    setSelectedIds((prev) => {
160	      const next = new Set(prev);
161	      if (next.has(id)) next.delete(id);
162	      else next.add(id);
163	      return next;
164	    });
165	  };
166	
167	  const toggleSelectAll = () => {
168	    if (isAllSelected) {
169	      setSelectedIds(new Set());
170	    } else {
171	      setSelectedIds(new Set(subscriptions.map((s) => s.id)));
172	    }
173	  };
174	
175	  const toggleChannel = (channelId: string) => {
176	    setCollapsedChannels((prev) => {
177	      const next = new Set(prev);
178	      if (next.has(channelId)) next.delete(channelId);
179	      else next.add(channelId);
180	      return next;
181	    });
182	  };
183	
184	  const toggleSelectChannel = (channelId: string) => {
185	    const channelSubs = grouped.get(channelId) ?? [];
186	    const channelSubIds = channelSubs.map((s) => s.id);
187	    const allSelected = channelSubIds.every((id) => selectedIds.has(id));
188	    setSelectedIds((prev) => {
189	      const next = new Set(prev);
190	      if (allSelected) {
191	        channelSubIds.forEach((id) => next.delete(id));
192	      } else {
193	        channelSubIds.forEach((id) => next.add(id));
194	      }
195	      return next;
196	    });
197	  };
198	
199	  const clearSelection = () => setSelectedIds(new Set());
200	
201	  return (
202	    <div className="space-y-6">
203	      {/* Header */}
204	      <div className="flex items-center justify-between">
205	        <div>
206	          <h1
207	            className="text-foreground"
208	            style={{
209	              fontFamily: "var(--font-raleway)",
210	              fontSize: "24px",
211	              fontWeight: 700,
212	            }}
213	          >
214	            {t("subscriptions.title")}
215	          </h1>
216	          <p className="mt-1 text-[13px] text-text-secondary" style={{ fontFamily: "var(--font-dm-sans)" }}>
217	            {t("subscriptions.description")}
218	          </p>
219	        </div>
220	        <button
221	          onClick={() => setCreateOpen(true)}
222	          className="inline-flex items-center gap-1.5 rounded-md px-3.5 py-2 transition-colors hover:opacity-90 bg-beacon-accent text-white"
223	          style={{
224	            fontFamily: "var(--font-dm-sans)",
225	            fontSize: "13px",
226	            fontWeight: 500,
227	          }}
228	        >
229	          <Plus className="h-4 w-4" />
230	          {t("subscriptions.newSubscription")}
231	        </button>
232	      </div>
233	
234	      {/* Filters */}
235	      <FilterBar filters={filterConfig} value={filters} onChange={setFilters} />
236	
237	      {isLoading ? (
238	        <div
239	          className="overflow-hidden rounded-lg bg-surface py-16 text-center border-border"
240	          style={{ border: "1px solid var(--border)", fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "var(--text-secondary)" }}
241	        >
242	          {t("subscriptions.loading")}
243	        </div>
244	      ) : subscriptions.length === 0 ? (
245	        <div
246	          className="overflow-hidden rounded-lg bg-surface py-16 text-center border-border"
247	          style={{ border: "1px solid var(--border)" }}
248	        >
249	          <p
250	            className="text-text-muted"
251	            style={{
252	              fontFamily: "var(--font-raleway)",
253	              fontStyle: "italic",
254	              fontSize: "15px",
255	            }}
256	          >
257	            {t("subscriptions.empty")}
258	          </p>
259	        </div>
260	      ) : (
261	        <>
262	          {/* Select all / batch bar */}
263	          <div
264	            className="flex items-center gap-3 rounded-lg bg-surface px-5 py-2.5"
265	            style={{ border: "1px solid var(--border)" }}
266	          >
267	            <Checkbox
268	              checked={isAllSelected ? true : isSomeSelected ? "indeterminate" : false}
269	              onCheckedChange={toggleSelectAll}
270	            />
271	            <span
272	              className="text-text-secondary"
273	              style={{
274	                fontFamily: "var(--font-dm-sans)",
275	                fontSize: "13px",
276	              }}
277	            >
278	              {selectedIds.size > 0
279	                ? t("subscriptions.selected").replace("{count}", String(selectedIds.size)).replace("{total}", String(subscriptions.length))
280	                : subscriptions.length === 1
281	                  ? t("subscriptions.countLabel").replace("{count}", String(subscriptions.length))
282	                  : t("subscriptions.countLabelPlural").replace("{count}", String(subscriptions.length))}
283	            </span>
284	            {selectedIds.size > 0 && (
285	              <button
286	                onClick={() => setBatchDeleteOpen(true)}
287	                className="ml-auto inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 transition-colors hover:opacity-90"
288	                style={{
289	                  backgroundColor: "#dc2626",
290	                  color: "#ffffff",
291	                  fontFamily: "var(--font-dm-sans)",
292	                  fontSize: "13px",
293	                  fontWeight: 500,
294	                }}
295	              >
296	                <Trash2 className="h-3.5 w-3.5" />
297	                {t("subscriptions.deleteSelected")}
298	              </button>
299	            )}
300	          </div>
301	
302	          {/* Grouped by channel */}
303	          <div className="space-y-3">
304	            {Array.from(grouped.entries()).map(([channelId, channelSubs]) => {
305	              const isCollapsed = collapsedChannels.has(channelId);
306	              const channelSubIds = channelSubs.map((s) => s.id);
307	              const allChannelSelected = channelSubIds.every((id) => selectedIds.has(id));
308	              const someChannelSelected = channelSubIds.some((id) => selectedIds.has(id)) && !allChannelSelected;
309	              const channelType = getChannelType(channelId);
310	
311	              return (
312	                <div
313	                  key={channelId}
314	                  className="overflow-hidden rounded-lg bg-surface"
315	                  style={{ border: "1px solid var(--border)" }}
316	                >
317	                  {/* Channel header */}
318	                  <div
319	                    className="flex items-center gap-3 px-5 py-3 cursor-pointer select-none bg-background"
320	                    style={{ borderBottom: isCollapsed ? "none" : "1px solid var(--border)" }}
321	                    onClick={() => toggleChannel(channelId)}
322	                  >
323	                    <div onClick={(e) => e.stopPropagation()}>
324	                      <Checkbox
325	                        checked={allChannelSelected ? true : someChannelSelected ? "indeterminate" : false}
326	                        onCheckedChange={() => toggleSelectChannel(channelId)}
327	                      />
328	                    </div>
329	                    <ChevronRight
330	                      className="h-4 w-4 transition-transform text-text-muted"
331	                      style={{
332	                        transform: isCollapsed ? "rotate(0deg)" : "rotate(90deg)",
333	                      }}
334	                    />
335	                    <span
336	                      className="text-foreground"
337	                      style={{
338	                        fontFamily: "var(--font-dm-sans)",
339	                        fontSize: "14px",
340	                        fontWeight: 600,
341	                      }}
342	                    >
343	                      {getChannelName(channelId)}
344	                    </span>
345	                    {channelType && (
346	                      <span
347	                        className="rounded-full px-2 py-0.5 text-text-secondary bg-mono-bg"
348	                        style={{
349	                          fontFamily: "var(--font-dm-sans)",
350	                          fontSize: "11px",
351	                          fontWeight: 500,
352	                        }}
353	                      >
354	                        {channelType}
355	                      </span>
356	                    )}
357	                    <span
358	                      className="text-text-muted"
359	                      style={{
360	                        fontFamily: "var(--font-dm-sans)",
361	                        fontSize: "12px",
362	                        marginLeft: "auto",
363	                      }}
364	                    >
365	                      {channelSubs.length === 1
366	                        ? t("subscriptions.channelSubscription").replace("{count}", String(channelSubs.length))
367	                        : t("subscriptions.channelSubscriptionPlural").replace("{count}", String(channelSubs.length))}
368	                    </span>
369	                  </div>
370	
371	                  {/* Subscription rows */}
372	                  {!isCollapsed && (
373	                    <table className="w-full">
374	                      <thead>
375	                        <tr>
376	                          {["", t("subscriptions.thType"), t("subscriptions.thTarget"), t("subscriptions.thVersionFilter"), ""].map(
377	                            (heading, i) => (
378	                              <th
379	                                key={i}
380	                                className={`py-2 text-left ${i === 0 ? "w-10 px-5" : i === 4 ? "w-20 px-5" : "px-5"}`}
381	                                style={{
382	                                  fontFamily: "var(--font-dm-sans)",
383	                                  fontSize: "11px",
384	                                  fontWeight: 500,
385	                                  textTransform: "uppercase",
386	                                  letterSpacing: "0.08em",
387	                                  color: "var(--text-muted)",
388	                                  borderBottom: "1px solid var(--border)",
389	                                }}
390	                              >
391	                                {heading}
392	                              </th>
393	                            )
394	                          )}
395	                        </tr>
396	                      </thead>
397	                      <tbody>
398	                        {channelSubs.map((sub) => (
399	                          <tr
400	                            key={sub.id}
401	                            className="transition-colors hover:bg-background"
402	                            style={{ borderBottom: "1px solid var(--border)" }}
403	                          >
404	                            {/* Checkbox */}
405	                            <td className="w-10 px-5 py-3">
406	                              <Checkbox
407	                                checked={selectedIds.has(sub.id)}
408	                                onCheckedChange={() => toggleSelect(sub.id)}
409	                              />
410	                            </td>
411	
412	                            {/* Type */}
413	                            <td className="px-5 py-3">
414	                              <SubTypeBadge type={sub.type} />
415	                            </td>
416	
417	                            {/* Target */}
418	                            <td
419	                              className="px-5 py-3 text-foreground"
420	                              style={{
421	                                fontFamily: "var(--font-dm-sans)",
422	                                fontSize: "14px",
423	                                fontWeight: 500,
424	                              }}
425	                            >
426	                              {sub.type === "source_release"
427	                                ? getSourceLabel(sub.source_id!)
428	                                : getProjectName(sub.project_id!)}
429	                            </td>
430	
431	                            {/* Version Filter */}
432	                            <td
433	                              className="px-5 py-3"
434	                              style={{
435	                                fontFamily: sub.version_filter
436	                                  ? "'JetBrains Mono', monospace"
437	                                  : "var(--font-dm-sans)",
438	                                fontSize: "13px",
439	                                color: sub.version_filter ? "var(--foreground)" : "var(--text-muted)",
440	                              }}
441	                            >
442	                              {sub.version_filter || "\u2014"}
443	                            </td>
444	
445	                            {/* Actions */}
446	                            <td className="w-20 px-5 py-3">
447	                              <div className="flex items-center gap-2">
448	                                <button
449	                                  onClick={() => setEditingSub(sub)}
450	                                  className="rounded p-1 text-text-muted transition-colors hover:bg-mono-bg hover:text-foreground"
451	                                >
452	                                  <Pencil className="h-4 w-4" />
453	                                </button>
454	                                <button
455	                                  onClick={() => setDeletingId(sub.id)}
456	                                  className="rounded p-1 text-text-muted transition-colors hover:bg-red-50 hover:text-red-600"
457	                                >
458	                                  <Trash2 className="h-4 w-4" />
459	                                </button>
460	                              </div>
461	                            </td>
462	                          </tr>
463	                        ))}
464	                      </tbody>
465	                    </table>
466	                  )}
467	                </div>
468	              );
469	            })}
470	          </div>
471	        </>
472	      )}
473	
474	      {/* Create dialog */}
475	      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
476	        <DialogContent className="sm:max-w-lg">
477	          <DialogHeader>
478	            <DialogTitle>{t("subscriptions.createSubscription")}</DialogTitle>
479	          </DialogHeader>
480	          <SubscriptionForm
481	            title={t("subscriptions.createSubscription")}
482	            onSubmit={async (input) => {
483	              await subsApi.create(input);
484	            }}
485	            onBatchSubmit={async (input) => {
486	              await subsApi.batchCreate(input);
487	            }}
488	            onSuccess={() => {
489	              setCreateOpen(false);
490	              mutate("subscriptions");
491	              clearSelection();
492	            }}
493	            onCancel={() => setCreateOpen(false)}
494	          />
495	        </DialogContent>
496	      </Dialog>
497	
498	      {/* Edit dialog */}
499	      <Dialog
500	        open={!!editingSub}
501	        onOpenChange={(open) => {
502	          if (!open) setEditingSub(null);
503	        }}
504	      >
505	        <DialogContent className="sm:max-w-lg">
506	          <DialogHeader>
507	            <DialogTitle>{t("subscriptions.editSubscription")}</DialogTitle>
508	          </DialogHeader>
509	          {editingSub && (
510	            <SubscriptionForm
511	              key={editingSub.id}
512	              title={t("subscriptions.editSubscription")}
513	              initial={editingSub}
514	              onSubmit={async (input) => {
515	                await subsApi.update(editingSub.id, input);
516	              }}
517	              onSuccess={() => {
518	                setEditingSub(null);
519	                mutate("subscriptions");
520	                clearSelection();
521	              }}
522	              onCancel={() => setEditingSub(null)}
523	            />
524	          )}
525	        </DialogContent>
526	      </Dialog>
527	
528	      {/* Delete dialog */}
529	      <ConfirmDialog
530	        open={!!deletingId}
531	        onOpenChange={(open) => {
532	          if (!open) setDeletingId(null);
533	        }}
534	        title={t("subscriptions.deleteSubscription")}
535	        description={t("subscriptions.deleteSubscriptionDesc")}
536	        onConfirm={async () => {
537	          if (deletingId) {
538	            await subsApi.delete(deletingId);
539	            mutate("subscriptions");
540	            clearSelection();
541	          }
542	        }}
543	      />
544	
545	      {/* Batch delete dialog */}
546	      <ConfirmDialog
547	        open={batchDeleteOpen}
548	        onOpenChange={setBatchDeleteOpen}
549	        title={t("subscriptions.deleteSubscriptions")}
550	        description={t("subscriptions.deleteSubscriptionsDesc").replace("{count}", String(selectedIds.size))}
551	        onConfirm={async () => {
552	          await subsApi.batchDelete({ ids: [...selectedIds] });
553	          mutate("subscriptions");
554	          clearSelection();
555	        }}
556	      />
557	    </div>
558	  );
559	}
