32	        backgroundColor: colors.bg,
33	        color: colors.text,
34	        fontFamily: "var(--font-dm-sans)",
35	        fontSize: "12px",
36	        fontWeight: 500,
37	        lineHeight: "16px",
38	      }}
39	    >
40	      {type}
41	    </span>
42	  );
43	}
44	
45	export default function SubscriptionsPage() {
46	  return (
47	    <Suspense>
48	      <SubscriptionsPageInner />
49	    </Suspense>
