52	
53	function SubscriptionsPageInner() {
54	  const { t } = useTranslation();
55	  const FILTER_KEYS = ["channel", "type"];
56	  const { filters, setFilters } = useFilterParams(FILTER_KEYS);
57	  const { data, isLoading } = useSWR("subscriptions", () => subsApi.list());
58	  const { data: channelsData } = useSWR("channels-for-sub-list", () =>
59	    channelsApi.list()
60	  );
61	  const { data: projectsData } = useSWR("projects-for-sub-list", () =>
62	    projectsApi.list(1, 100)
63	  );
64	
65	  // Collect unique source IDs from subscriptions and fetch each one
66	  const sourceIds = useMemo(
67	    () =>
68	      Array.from(
69	        new Set(
70	          (data?.data ?? [])
71	            .filter((s) => s.type === "source_release" && s.source_id)
72	            .map((s) => s.source_id!)
73	        )
74	      ),
75	    [data]
76	  );
77	  const { data: sourcesMap } = useSWR(
78	    sourceIds.length > 0 ? `sources-for-sub-list-${sourceIds.join(",")}` : null,
79	    async () => {
80	      const results = await Promise.all(
81	        sourceIds.map((id) => sourcesApi.get(id).catch(() => null))
82	      );
83	      const map: Record<string, Source> = {};
84	      for (const r of results) {
85	        if (r?.data) map[r.data.id] = r.data;
86	      }
87	      return map;
88	    }
89	  );
90	
91	  const [createOpen, setCreateOpen] = useState(false);
92	  const [editingSub, setEditingSub] = useState<Subscription | null>(null);
93	  const [deletingId, setDeletingId] = useState<string | null>(null);
94	  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
95	  const [batchDeleteOpen, setBatchDeleteOpen] = useState(false);
96	  const [collapsedChannels, setCollapsedChannels] = useState<Set<string>>(new Set());
97	
98	  const getChannelName = (id: string) =>
99	    channelsData?.data.find((c) => c.id === id)?.name ?? id;
100	
101	  const getChannelType = (id: string) =>
102	    channelsData?.data.find((c) => c.id === id)?.type ?? "";
103	
104	  const getProjectName = (id: string) =>
105	    projectsData?.data.find((p) => p.id === id)?.name ?? id;
106	
107	  const getSourceLabel = (id: string) => {
108	    const source = sourcesMap?.[id];
109	    return source ? `${source.provider}: ${source.repository}` : id;
110	  };
111	
112	  /* Build filter config */
113	  const filterConfig: FilterConfig[] = useMemo(() => [
114	    {
115	      key: "channel",
116	      label: "Channel",
117	      type: "select" as const,
118	      options: (channelsData?.data ?? []).map((c) => ({ value: c.id, label: c.name })),
119	    },
120	    {
121	      key: "type",
122	      label: "Type",
123	      type: "select" as const,
124	      options: [
125	        { value: "source_release", label: "Source Release" },
126	        { value: "semantic_release", label: "Semantic Release" },
127	      ],
128	    },
129	  ], [channelsData]);
130	
131	  /* Client-side filtering */
132	  const allSubscriptions = data?.data ?? [];
133	  const subscriptions = useMemo(() => {
134	    let result = allSubscriptions;
135	    if (filters.channel) {
136	      result = result.filter((s) => s.channel_id === filters.channel);
137	    }
138	    if (filters.type) {
139	      result = result.filter((s) => s.type === filters.type);
140	    }
141	    return result;
142	  }, [allSubscriptions, filters.channel, filters.type]);
143	
144	  // Group subscriptions by channel_id
145	  const grouped = useMemo(() => {
146	    const map = new Map<string, Subscription[]>();
147	    for (const sub of subscriptions) {
148	      const list = map.get(sub.channel_id) ?? [];
149	      list.push(sub);
150	      map.set(sub.channel_id, list);
151	    }
152	    return map;
153	  }, [subscriptions]);
154	
155	  const isAllSelected = subscriptions.length > 0 && selectedIds.size === subscriptions.length;
156	  const isSomeSelected = selectedIds.size > 0 && !isAllSelected;
157	
158	  const toggleSelect = (id: string) => {
159	    setSelectedIds((prev) => {
160	      const next = new Set(prev);
161	      if (next.has(id)) next.delete(id);
162	      else next.add(id);
163	      return next;
164	    });
165	  };
166	
167	  const toggleSelectAll = () => {
168	    if (isAllSelected) {
169	      setSelectedIds(new Set());
170	    } else {
171	      setSelectedIds(new Set(subscriptions.map((s) => s.id)));
172	    }
173	  };
174	
175	  const toggleChannel = (channelId: string) => {
176	    setCollapsedChannels((prev) => {
177	      const next = new Set(prev);
178	      if (next.has(channelId)) next.delete(channelId);
179	      else next.add(channelId);
180	      return next;
181	    });
182	  };
183	
184	  const toggleSelectChannel = (channelId: string) => {
185	    const channelSubs = grouped.get(channelId) ?? [];
186	    const channelSubIds = channelSubs.map((s) => s.id);
187	    const allSelected = channelSubIds.every((id) => selectedIds.has(id));
188	    setSelectedIds((prev) => {
189	      const next = new Set(prev);
190	      if (allSelected) {
191	        channelSubIds.forEach((id) => next.delete(id));
192	      } else {
193	        channelSubIds.forEach((id) => next.add(id));
194	      }
195	      return next;
196	    });
197	  };
198	
199	  const clearSelection = () => setSelectedIds(new Set());
200	
201	  return (
202	    <div className="space-y-6">
203	      {/* Header */}
204	      <div className="flex items-center justify-between">
205	        <div>
206	          <h1
207	            className="text-foreground"
208	            style={{
209	              fontFamily: "var(--font-raleway)",
210	              fontSize: "24px",
211	              fontWeight: 700,
212	            }}
213	          >
214	            {t("subscriptions.title")}
215	          </h1>
216	          <p className="mt-1 text-[13px] text-text-secondary" style={{ fontFamily: "var(--font-dm-sans)" }}>
217	            {t("subscriptions.description")}
218	          </p>
219	        </div>
220	        <button
221	          onClick={() => setCreateOpen(true)}
222	          className="inline-flex items-center gap-1.5 rounded-md px-3.5 py-2 transition-colors hover:opacity-90 bg-beacon-accent text-white"
223	          style={{
224	            fontFamily: "var(--font-dm-sans)",
225	            fontSize: "13px",
226	            fontWeight: 500,
227	          }}
228	        >
229	          <Plus className="h-4 w-4" />
230	          {t("subscriptions.newSubscription")}
231	        </button>
232	      </div>
233	
234	      {/* Combined filter + selection ribbon */}
235	      <div
236	        className="flex flex-wrap items-center gap-2 rounded-lg border border-border bg-surface px-3 py-2"
237	      >
238	        {!isLoading && subscriptions.length > 0 && (
239	          <Checkbox
240	            checked={isAllSelected ? true : isSomeSelected ? "indeterminate" : false}
241	            onCheckedChange={toggleSelectAll}
242	          />
243	        )}
244	        {!isLoading && (
245	          <span
246	            className="text-text-secondary"
247	            style={{
248	              fontFamily: "var(--font-dm-sans)",
249	              fontSize: "13px",
250	            }}
251	          >
252	            {selectedIds.size > 0
253	              ? t("subscriptions.selected").replace("{count}", String(selectedIds.size)).replace("{total}", String(subscriptions.length))
254	              : subscriptions.length === 1
255	                ? t("subscriptions.countLabel").replace("{count}", String(subscriptions.length))
256	                : t("subscriptions.countLabelPlural").replace("{count}", String(subscriptions.length))}
257	          </span>
258	        )}
259	        <span className="mx-1 h-4 w-px bg-border" />
260	        <FilterBar filters={filterConfig} value={filters} onChange={setFilters} inline />
261	        {selectedIds.size > 0 && (
262	          <button
263	            onClick={() => setBatchDeleteOpen(true)}
264	            className="ml-auto inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 transition-colors hover:opacity-90"
265	            style={{
266	              backgroundColor: "#dc2626",
267	              color: "#ffffff",
268	              fontFamily: "var(--font-dm-sans)",
269	              fontSize: "13px",
270	              fontWeight: 500,
271	            }}
272	          >
273	            <Trash2 className="h-3.5 w-3.5" />
274	            {t("subscriptions.deleteSelected")}
275	          </button>
276	        )}
277	      </div>
278	
279	      {isLoading ? (
280	        <div
281	          className="overflow-hidden rounded-lg bg-surface py-16 text-center border-border"
282	          style={{ border: "1px solid var(--border)", fontFamily: "var(--font-dm-sans)", fontSize: "13px", color: "var(--text-secondary)" }}
283	        >
284	          {t("subscriptions.loading")}
285	        </div>
286	      ) : subscriptions.length === 0 ? (
287	        <div
288	          className="overflow-hidden rounded-lg bg-surface py-16 text-center border-border"
289	          style={{ border: "1px solid var(--border)" }}
290	        >
291	          <p
292	            className="text-text-muted"
293	            style={{
294	              fontFamily: "var(--font-raleway)",
295	              fontStyle: "italic",
296	              fontSize: "15px",
297	            }}
298	          >
299	            {t("subscriptions.empty")}
300	          </p>
301	        </div>
302	      ) : (
303	        <>
304	          {/* Grouped by channel */}
305	          <div className="space-y-3">
306	            {Array.from(grouped.entries()).map(([channelId, channelSubs]) => {
307	              const isCollapsed = collapsedChannels.has(channelId);
308	              const channelSubIds = channelSubs.map((s) => s.id);
309	              const allChannelSelected = channelSubIds.every((id) => selectedIds.has(id));
310	              const someChannelSelected = channelSubIds.some((id) => selectedIds.has(id)) && !allChannelSelected;
311	              const channelType = getChannelType(channelId);
312	
313	              return (
314	                <div
315	                  key={channelId}
316	                  className="overflow-hidden rounded-lg bg-surface"
317	                  style={{ border: "1px solid var(--border)" }}
318	                >
319	                  {/* Channel header */}
320	                  <div
321	                    className="flex items-center gap-3 px-5 py-3 cursor-pointer select-none bg-background"
322	                    style={{ borderBottom: isCollapsed ? "none" : "1px solid var(--border)" }}
323	                    onClick={() => toggleChannel(channelId)}
324	                  >
325	                    <div onClick={(e) => e.stopPropagation()}>
326	                      <Checkbox
327	                        checked={allChannelSelected ? true : someChannelSelected ? "indeterminate" : false}
328	                        onCheckedChange={() => toggleSelectChannel(channelId)}
329	                      />
330	                    </div>
331	                    <ChevronRight
332	                      className="h-4 w-4 transition-transform text-text-muted"
333	                      style={{
334	                        transform: isCollapsed ? "rotate(0deg)" : "rotate(90deg)",
335	                      }}
336	                    />
337	                    <span
338	                      className="text-foreground"
339	                      style={{
340	                        fontFamily: "var(--font-dm-sans)",
341	                        fontSize: "14px",
342	                        fontWeight: 600,
343	                      }}
344	                    >
345	                      {getChannelName(channelId)}
346	                    </span>
347	                    {channelType && (
348	                      <span
349	                        className="rounded-full px-2 py-0.5 text-text-secondary bg-mono-bg"
350	                        style={{
351	                          fontFamily: "var(--font-dm-sans)",
352	                          fontSize: "11px",
353	                          fontWeight: 500,
354	                        }}
355	                      >
356	                        {channelType}
357	                      </span>
358	                    )}
359	                    <span
360	                      className="text-text-muted"
361	                      style={{
362	                        fontFamily: "var(--font-dm-sans)",
363	                        fontSize: "12px",
364	                        marginLeft: "auto",
365	                      }}
366	                    >
367	                      {channelSubs.length === 1
368	                        ? t("subscriptions.channelSubscription").replace("{count}", String(channelSubs.length))
369	                        : t("subscriptions.channelSubscriptionPlural").replace("{count}", String(channelSubs.length))}
370	                    </span>
371	                  </div>
372	
373	                  {/* Subscription rows */}
374	                  {!isCollapsed && (
375	                    <table className="w-full">
376	                      <thead>
377	                        <tr>
378	                          {["", t("subscriptions.thType"), t("subscriptions.thTarget"), t("subscriptions.thVersionFilter"), ""].map(
379	                            (heading, i) => (
380	                              <th
381	                                key={i}
382	                                className={`py-2 text-left ${i === 0 ? "w-10 px-5" : i === 4 ? "w-20 px-5" : "px-5"}`}
383	                                style={{
384	                                  fontFamily: "var(--font-dm-sans)",
385	                                  fontSize: "11px",
386	                                  fontWeight: 500,
387	                                  textTransform: "uppercase",
388	                                  letterSpacing: "0.08em",
389	                                  color: "var(--text-muted)",
390	                                  borderBottom: "1px solid var(--border)",
391	                                }}
392	                              >
393	                                {heading}
394	                              </th>
395	                            )
396	                          )}
397	                        </tr>
398	                      </thead>
399	                      <tbody>
400	                        {channelSubs.map((sub) => (
401	                          <tr
402	                            key={sub.id}
403	                            className="transition-colors hover:bg-background"
404	                            style={{ borderBottom: "1px solid var(--border)" }}
405	                          >
406	                            {/* Checkbox */}
407	                            <td className="w-10 px-5 py-3">
408	                              <Checkbox
409	                                checked={selectedIds.has(sub.id)}
410	                                onCheckedChange={() => toggleSelect(sub.id)}
411	                              />
412	                            </td>
413	
414	                            {/* Type */}
415	                            <td className="px-5 py-3">
416	                              <SubTypeBadge type={sub.type} />
417	                            </td>
418	
419	                            {/* Target */}
420	                            <td
421	                              className="px-5 py-3 text-foreground"
422	                              style={{
423	                                fontFamily: "var(--font-dm-sans)",
424	                                fontSize: "14px",
425	                                fontWeight: 500,
426	                              }}
427	                            >
428	                              {sub.type === "source_release"
429	                                ? getSourceLabel(sub.source_id!)
430	                                : getProjectName(sub.project_id!)}
431	                            </td>
432	
433	                            {/* Version Filter */}
434	                            <td
435	                              className="px-5 py-3"
436	                              style={{
437	                                fontFamily: sub.version_filter
438	                                  ? "'JetBrains Mono', monospace"
439	                                  : "var(--font-dm-sans)",
440	                                fontSize: "13px",
441	                                color: sub.version_filter ? "var(--foreground)" : "var(--text-muted)",
442	                              }}
443	                            >
444	                              {sub.version_filter || "\u2014"}
445	                            </td>
446	
447	                            {/* Actions */}
448	                            <td className="w-20 px-5 py-3">
449	                              <div className="flex items-center gap-2">
450	                                <button
451	                                  onClick={() => setEditingSub(sub)}
452	                                  className="rounded p-1 text-text-muted transition-colors hover:bg-mono-bg hover:text-foreground"
453	                                >
454	                                  <Pencil className="h-4 w-4" />
455	                                </button>
456	                                <button
457	                                  onClick={() => setDeletingId(sub.id)}
458	                                  className="rounded p-1 text-text-muted transition-colors hover:bg-red-50 hover:text-red-600"
459	                                >
460	                                  <Trash2 className="h-4 w-4" />
461	                                </button>
462	                              </div>
463	                            </td>
464	                          </tr>
465	                        ))}
466	                      </tbody>
467	                    </table>
468	                  )}
469	                </div>
470	              );
471	            })}
472	          </div>
473	        </>
474	      )}
475	
476	      {/* Create dialog */}
477	      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
478	        <DialogContent className="sm:max-w-lg">
479	          <DialogHeader>
480	            <DialogTitle>{t("subscriptions.createSubscription")}</DialogTitle>
481	          </DialogHeader>
482	          <SubscriptionForm
483	            title={t("subscriptions.createSubscription")}
484	            onSubmit={async (input) => {
485	              await subsApi.create(input);
486	            }}
487	            onBatchSubmit={async (input) => {
488	              await subsApi.batchCreate(input);
489	            }}
490	            onSuccess={() => {
491	              setCreateOpen(false);
492	              mutate("subscriptions");
493	              clearSelection();
494	            }}
495	            onCancel={() => setCreateOpen(false)}
496	          />
497	        </DialogContent>
498	      </Dialog>
499	
500	      {/* Edit dialog */}
501	      <Dialog
502	        open={!!editingSub}
503	        onOpenChange={(open) => {
504	          if (!open) setEditingSub(null);
505	        }}
506	      >
507	        <DialogContent className="sm:max-w-lg">
508	          <DialogHeader>
509	            <DialogTitle>{t("subscriptions.editSubscription")}</DialogTitle>
510	          </DialogHeader>
511	          {editingSub && (
512	            <SubscriptionForm
513	              key={editingSub.id}
514	              title={t("subscriptions.editSubscription")}
515	              initial={editingSub}
516	              onSubmit={async (input) => {
517	                await subsApi.update(editingSub.id, input);
518	              }}
519	              onSuccess={() => {
520	                setEditingSub(null);
521	                mutate("subscriptions");
522	                clearSelection();
523	              }}
524	              onCancel={() => setEditingSub(null)}
525	            />
526	          )}
